  ('aboriginal-0a2fc18c-moex-00352', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-110-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '如果短期的總合供給線為一條正斜率的曲線，長期的總合供給線為一條垂直線，則總合需求的改 變將會：', '["不影響短期產出與長期產出", "同時影響短期產出與長期產出", "只影響短期產出，但不影響長期產出", "只影響長期產出，但不影響短期產出"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:42+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "405", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL)
